"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[20077],{35709:e=>{e.exports=JSON.parse('{"tag":{"label":"sanity","permalink":"/dst-api-webdocs/docs/tags/sanity","allTagsPath":"/dst-api-webdocs/docs/tags","count":17,"items":[{"id":"game-scripts/brains/berniebrain","title":"Berniebrain","description":"Manages the AI behavior of Bernie the Big Bernie, including detecting when to transform, finding a leader to follow, taunting nearby sanity monsters, and switching between wandering and following states.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/berniebrain"},{"id":"game-scripts/components/book","title":"Book","description":"Manages interactive reading and perusing behavior for books, including sanity effects, use consumption, and optional visual FX.","permalink":"/dst-api-webdocs/docs/game-scripts/components/book"},{"id":"game-scripts/components/brightmarespawner","title":"Brightmarespawner","description":"Tracks players in Lunacy Mode and periodically spawns Brightmare Gestalt entities based on player sanity levels and population rules.","permalink":"/dst-api-webdocs/docs/game-scripts/components/brightmarespawner"},{"id":"game-scripts/components/coach","title":"Coach","description":"Provides periodic support effects (sanity and fight buffs) to nearby players and followers when the host entity is tagged as \\"coaching\\".","permalink":"/dst-api-webdocs/docs/game-scripts/components/coach"},{"id":"game-scripts/components/firebug","title":"Firebug","description":"Triggers periodic announcements and spawns a prefab when an entity\'s fire timer expires, optionally subject to sanity thresholds.","permalink":"/dst-api-webdocs/docs/game-scripts/components/firebug"},{"id":"game-scripts/components/hallucinations","title":"Hallucinations","description":"Manages the spawning and tracking of hallucination entities based on player sanity, time of day, and environment lighting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hallucinations"},{"id":"game-scripts/components/itemaffinity","title":"Itemaffinity","description":"Manages a priority-based sanity bonus for characters based on specific items carried in inventory.","permalink":"/dst-api-webdocs/docs/game-scripts/components/itemaffinity"},{"id":"game-scripts/components/reader","title":"Reader","description":"Enables an entity to read books and track bookworm status and sanity penalties.","permalink":"/dst-api-webdocs/docs/game-scripts/components/reader"},{"id":"game-scripts/components/sanity","title":"Sanity","description":"Manages sanity value, mode (Insanity/Lunacy), and related mechanics for an entity, including dynamic rate calculation from environmental and aura sources.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanity"},{"id":"game-scripts/components/sanity_replica","title":"Sanity Replica","description":"Network-replicated component that synchronizes sanity state, mode, and related properties between server and client for player entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanity_replica"},{"id":"game-scripts/map/static_layouts/sanity_wormhole_1","title":"Sanity Wormhole 1","description":"Defines a static 16x16 tilemap layout containing sanity rocks and a central wormhole object for use in world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/sanity_wormhole_1"},{"id":"game-scripts/components/sanityaura","title":"Sanityaura","description":"Computes and provides sanity-affecting aura values for an entity within a defined radius.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanityaura"},{"id":"game-scripts/components/sanityauraadjuster","title":"Sanityauraadjuster","description":"Manages periodic adjustment of sanity aura effects by running a custom callback function on a timer.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sanityauraadjuster"},{"id":"game-scripts/components/shadowcreaturespawner","title":"Shadowcreaturespawner","description":"Manages the spawning, tracking, and population control of shadow creatures (e.g., Crawling Horrors, Ocean Horrors, Terrorbeaks) for players based on sanity levels and game mode.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowcreaturespawner"},{"id":"game-scripts/components/staffsanity","title":"Staffsanity","description":"Modifies the rate of sanity change when used as a staff-like item to cast abilities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/staffsanity"},{"id":"game-scripts/components/transparentonsanity","title":"Transparentonsanity","description":"Adjusts an entity\'s transparency and sound volume based on the player\'s sanity and combat state, with optional custom logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/transparentonsanity"},{"id":"game-scripts/brains/waveyjoneshandbrain","title":"Waveyjoneshandbrain","description":"Controls the behavior of Wavey Jones\' hand entity by selecting and performing repair-related actions on boat components based on current conditions and player sanity.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/waveyjoneshandbrain"}],"unlisted":false}}')}}]);